import React, { useState, useEffect } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { clearAuth } from '../api';
import { 
  Menu, X, Home, MessageSquare, 
  AlertTriangle, Bell, Users, LogOut, 
  ChevronRight, Sparkles, Command
} from 'lucide-react';

const navItems = [
  { name: 'Home',      path: '/user/home',      icon: Home },
  { name: 'Feedback',  path: '/user/feedback',  icon: MessageSquare },
  { name: 'Complaint', path: '/user/complaint', icon: AlertTriangle },
  { name: 'Notices',   path: '/user/notices',   icon: Bell },
  { name: 'Societies', path: '/user/societies', icon: Users },
];

const Navbar = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const [menuOpen, setMenuOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleLogout = () => {
    clearAuth();
    navigate('/login');
  };

  return (
    <nav className={`fixed top-0 left-0 right-0 z-[1000] transition-all duration-500 ${
      scrolled ? 'py-3 px-4' : 'py-6 px-8'
    }`}>
      {/* Glossy Background Layer */}
      <div className={`mx-auto max-w-7xl transition-all duration-500 rounded-[24px] border border-white/5 relative overflow-hidden ${
        scrolled 
          ? 'bg-slate-950/40 backdrop-blur-2xl shadow-[0_8px_32px_0_rgba(0,0,0,0.8)]' 
          : 'bg-transparent backdrop-blur-sm'
      }`}>

        {/* Top Highlight Line (Premium Detail) */}
        <div className="absolute top-0 left-0 right-0 h-px bg-gradient-to-r from-transparent via-white/10 to-transparent" />

        <div className="flex h-16 items-center justify-between px-8">

          {/* Enhanced Logo */}
          <motion.div 
            whileHover={{ scale: 1.02 }}
            whileTap={{ scale: 0.98 }}
            className="flex cursor-pointer items-center gap-3 group" 
            onClick={() => navigate('/user/home')}
          >
            <div className="relative flex h-11 w-11 items-center justify-center rounded-xl bg-gradient-to-br from-amber-400 to-orange-600 shadow-lg shadow-amber-500/20">
              <Sparkles size={22} className="text-slate-950 fill-current" />
              <div className="absolute inset-0 rounded-xl bg-white/20 animate-pulse" />
            </div>
            <div className="flex flex-col leading-none">
              <span className="text-xl font-black tracking-tighter text-white uppercase italic">
                Hostel<span className="text-amber-500">Mate</span>
              </span>
              <span className="text-[9px] font-bold tracking-[0.3em] text-slate-500 uppercase">
                Dashboard
              </span>
            </div>
          </motion.div>

          {/* Desktop Navigation Pills */}
          <div className="hidden lg:flex items-center gap-1 bg-white/[0.03] p-1.5 rounded-2xl border border-white/5 shadow-inner">
            {navItems.map(({ name, path, icon: Icon }) => {
              const isActive = location.pathname === path;
              return (
                <Link key={path} to={path} className="relative px-5 py-2.5 outline-none transition-colors group">
                  <div className={`flex items-center gap-2.5 text-sm font-bold transition-all duration-300 relative z-10 ${
                    isActive ? 'text-slate-950' : 'text-slate-400 hover:text-white'
                  }`}>
                    <Icon size={18} strokeWidth={isActive ? 2.5 : 2} />
                    <span>{name}</span>
                  </div>

                  {/* Magnetic Active Background */}
                  {isActive && (
                    <motion.div 
                      layoutId="active-pill"
                      className="absolute inset-0 bg-amber-400 rounded-xl shadow-[0_0_20px_rgba(251,191,36,0.3)]"
                      transition={{ type: "spring", stiffness: 380, damping: 30 }}
                    />
                  )}
                </Link>
              );
            })}
          </div>

          {/* Right Action Section */}
          <div className="flex items-center gap-4">
            {/* Quick Command Button (Premium Detail) */}
            <div className="hidden sm:flex h-10 w-10 items-center justify-center rounded-xl bg-white/5 border border-white/10 text-slate-500 cursor-help hover:text-amber-500 transition-colors">
               <Command size={18} />
            </div>

            <button 
              onClick={handleLogout}
              className="hidden md:flex items-center gap-2 rounded-xl bg-gradient-to-b from-red-500/10 to-red-600/5 px-6 py-2.5 text-xs font-black uppercase tracking-widest text-red-500 border border-red-500/20 shadow-lg shadow-red-500/5 transition-all hover:from-red-500 hover:to-red-600 hover:text-white hover:shadow-red-500/20"
            >
              <LogOut size={16} />
              Sign Out
            </button>

            {/* Mobile Menu Button */}
            <motion.button
              whileTap={{ scale: 0.9 }}
              onClick={() => setMenuOpen(!menuOpen)}
              className="lg:hidden flex h-11 w-11 items-center justify-center rounded-xl bg-white/5 text-amber-500 border border-white/10 shadow-lg"
            >
              <AnimatePresence mode="wait">
                {menuOpen ? <X key="x" size={24} /> : <Menu key="m" size={24} />}
              </AnimatePresence>
            </motion.button>
          </div>
        </div>
      </div>

      {/* Mobile Sidebar Overlay */}
      <AnimatePresence>
        {menuOpen && (
          <>
            {/* Backdrop Blur */}
            <motion.div 
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              onClick={() => setMenuOpen(false)}
              className="fixed inset-0 bg-black/60 backdrop-blur-md lg:hidden"
            />

            {/* Sidebar Content */}
            <motion.div
              initial={{ x: '100%' }}
              animate={{ x: 0 }}
              exit={{ x: '100%' }}
              transition={{ type: 'spring', damping: 25, stiffness: 200 }}
              className="fixed top-0 right-0 bottom-0 w-[80%] max-w-sm bg-slate-950 border-l border-white/10 p-8 flex flex-col lg:hidden z-[1001]"
            >
              <div className="flex items-center justify-between mb-12">
                 <div className="flex items-center gap-3">
                    <div className="h-10 w-10 rounded-lg bg-amber-500 flex items-center justify-center">
                       <Sparkles size={20} className="text-black fill-current" />
                    </div>
                    <span className="font-black text-white italic">MENU</span>
                 </div>
                 <X size={24} className="text-slate-500" onClick={() => setMenuOpen(false)} />
              </div>

              <div className="flex flex-col gap-3 flex-grow">
                {navItems.map(({ name, path, icon: Icon }) => {
                  const isActive = location.pathname === path;
                  return (
                    <Link
                      key={path}
                      to={path}
                      onClick={() => setMenuOpen(false)}
                      className={`flex items-center justify-between rounded-2xl px-6 py-5 transition-all duration-300 ${
                        isActive 
                          ? 'bg-amber-500 text-slate-950 font-black shadow-[0_10px_20px_rgba(251,191,36,0.2)]' 
                          : 'bg-white/5 text-slate-400 hover:bg-white/10'
                      }`}
                    >
                      <div className="flex items-center gap-4 text-base tracking-tight">
                        <Icon size={22} strokeWidth={isActive ? 3 : 2} />
                        {name}
                      </div>
                      <ChevronRight size={18} className={isActive ? 'opacity-100' : 'opacity-20'} />
                    </Link>
                  );
                })}
              </div>

              <div className="mt-auto">
                <button
                  onClick={handleLogout}
                  className="flex w-full items-center justify-center gap-3 rounded-2xl bg-red-500 px-6 py-5 text-base font-black text-white shadow-xl shadow-red-900/20 active:scale-95 transition-all"
                >
                  <LogOut size={22} />
                  SIGN OUT
                </button>
                <p className="mt-6 text-center text-[10px] uppercase tracking-[0.3em] text-slate-600 font-bold">
                  HostelMate v2.0
                </p>
              </div>
            </motion.div>
          </>
        )}
      </AnimatePresence>
    </nav>
  );
};

export default Navbar;
